func:
/*
Here we will add the values to the payload which are needed for HA Gielz sensors and automation

To test this proxy, run:
% curl http://192.168.2.246:1880/properties/report
(or the applicable url)

To access original nodes:
% curl http://192.168.2.220/properties/report
% curl http://192.168.2.217/properties/report

*/



// read serial numbers from global variable
var snZendure1 = flow.get('snZendure1')||"0";
var snZendure2 = flow.get('snZendure2')||"0";

// load global variables
var latestPowerCmd = flow.get('latestPowerCmd') || 0;
var latestPowerCmd_1 = flow.get('latestPowerCmd_1') || 0;
var latestPowerCmd_2 = flow.get('latestPowerCmd_2') || 0;
var singleMode = flow.get('singleMode')||0;                              //0: no singlemode (dual mode), 1: singlemode
var singleMode_activedevice = flow.get('singleMode_activedevice')||0;    //0: device1, 1: device2
var singleMode_standby_device_A = flow.get('singleMode_standby_device_A')||0;
var singleMode_standby_device_B = flow.get('singleMode_standby_device_B')||0;
var dualMode_force_start_timestamp = flow.get('dualMode_force_start_timestamp') || 1;
var singleToDualModeTransition_start_timestamp = flow.get('singleToDualModeTransition_start_timestamp') || 1;
var singleModeDeviceChangeTranstion_timer = flow.get('singleModeDeviceChangeTranstion_timer') || 1;
var singleMode_upperlimit_percent = flow.get('singleMode_upperlimit_percent') || 100;
var singleMode_lowerlimit_percent = flow.get('singleMode_lowerlimit_percent') || 40;
var payloadError = flow.get('payloadError') || 0;
var equalMode = flow.get('equalMode') || 0;
var alwaysDualMode = flow.get('alwaysDualMode') || 0;
var solarPowerInfo = flow.get('solarPowerInfo') || 0;
var proxyVersion = flow.get('proxyVersion') || "0";
var dualmode_damper_enable = flow.get('dualmode_damper_enable')||0;

// Initialize local variables
let electricLevel_A = 0;
let electricLevel_B = 0;
let electricLevel = 0;
let deviceTransition_active = 0;
let sn_A = "";
let sn_B = "";


//Create a new json object to store the original and new values
let values = {}
values.properties = {}
values.original = {}



//// add back req/res for the reply to HA

let key = "http_" + msg._msgid;
let http = flow.get(key);

if (!http) {
    //node.warn("HTTP context not found");
    return null;
}
msg.req = http.req;
msg.res = http.res;

// cleanup key
flow.set(key, null);


///// New logic for ordering

let dev1 = msg.payload.zendure1;
let dev2 = msg.payload.zendure2;

if (!dev1 || !dev2) {

    if (!dev1 && !dev2) {
        //node.warn("Beide Zendures ontbreken in de join.");
    } else if (!dev1) {
        //node.warn("Zendure1 ontbreekt in de join.");
    } else if (!dev2) {
        //node.warn("Zendure2 ontbreekt in de join.");
    }
    return null;
}

if (dev1.sn !== snZendure1 || dev2.sn !== snZendure2) {
    //node.warn(`Serienummers komen niet overeen. Ingesteld: ${snZendure1}, ${snZendure2} – Gevonden: ${dev1.sn}, ${dev2.sn}`);
    return null;
}

// Deep clone originals
values.original[0] = JSON.parse(JSON.stringify(dev1));
values.original[1] = JSON.parse(JSON.stringify(dev2));

///// einde changed logic for ordering

// move battery packdata from original data to root level, as if it is one device
// non-deep clone for speed optimization

let packData1 = [...values.original[0].packData];
let packData2 = [...values.original[1].packData];

let packData = [...packData1, ...packData2]
values.packData = packData


// update current SoC levels to global variable
electricLevel_A = (values.original[0].properties.electricLevel)
electricLevel_B = (values.original[1].properties.electricLevel)
flow.set('electricLevel_A', electricLevel_A)
flow.set('electricLevel_B', electricLevel_B)

// write time of this message to variable for use in "Resend POST"  
let currentTime = Math.floor(Date.now() / 1000)
flow.set('latestGETMessage_timestamp_epoch', currentTime)

// Calculate max power value used in power distribution calculation in POST messages
// maxpower can be different for in and out directions
// first get the values that are configured on the Zendures 
let chargeMaxLimit_A = values.original[0].properties.chargeMaxLimit
let chargeMaxLimit_B = values.original[1].properties.chargeMaxLimit
let inverseMaxPower_A = values.original[0].properties.inverseMaxPower
let inverseMaxPower_B = values.original[1].properties.inverseMaxPower
// then calculate maxpower
let maxPower_in = Math.min(chargeMaxLimit_A, chargeMaxLimit_B)
let maxPower_out = Math.min(inverseMaxPower_A, inverseMaxPower_B)
flow.set('maxPower_in', maxPower_in)
flow.set('maxPower_out', maxPower_out)



// Version
values.proxyVersion = proxyVersion


//----- here all variables to send to HA in the response for the combined nodes


// product - we'll take the product string given by the device (Zendure 1). 
// Gielz uses this product name to determine the battery size, hence it has the be the actual product string.
let product = values.original[0].product || values.original[1].product;
values.product = product

// outputLimit (Output power limit)
let outputLimit = (values.original[0].properties.outputLimit + values.original[1].properties.outputLimit);
values.properties.outputLimit = outputLimit;

// inputLimit (AC charging power limit)
let inputLimit = (values.original[0].properties.inputLimit + values.original[1].properties.inputLimit);
values.properties.inputLimit = inputLimit;

// acMode (as this may be different on each node, best obtain it from a global variable, set by the POST messages to Zendure. Then at least it will be logical for HA)
// 1: Input, 2: Output
let acMode = null

if (singleMode === 1) {
    if (singleMode_activedevice === 0) {
        values.properties.acMode = values.original[0].properties.acMode;
    } else {
        values.properties.acMode = values.original[1].properties.acMode;
    }
} else {
    acMode = (values.original[0].properties.acMode + values.original[1].properties.acMode) / 2;
    values.properties.acMode = Math.floor(acMode);
}


// outputPackPower
let outputPackPower_A = values.original[0].properties.outputPackPower;
let outputPackPower_B = values.original[1].properties.outputPackPower;

let outputPackPower = (outputPackPower_A + outputPackPower_B);
values.properties.outputPackPower = outputPackPower;

// packInputPower
let packInputPower_A = values.original[0].properties.packInputPower;
let packInputPower_B = values.original[1].properties.packInputPower;

let packInputPower = (packInputPower_A + packInputPower_B);
values.properties.packInputPower = packInputPower;

// outputPackPower (same as outputPackPower for SF2400AC, but can be different on systems with solar attached)
let gridInputPower_A = values.original[0].properties.gridInputPower;
let gridInputPower_B = values.original[1].properties.gridInputPower;

let gridInputPower = (gridInputPower_A + gridInputPower_B);
values.properties.gridInputPower = gridInputPower;

// outputHomePower (same as packInputPower for SF2400AC, but can be different on systems with solar attached)
let outputHomePower_A = values.original[0].properties.outputHomePower;
let outputHomePower_B = values.original[1].properties.outputHomePower;

let outputHomePower = (outputHomePower_A + outputHomePower_B);
values.properties.outputHomePower = outputHomePower;

// minSoc - select largest one
let minSoc_A = values.original[0].properties.minSoc;
let minSoc_B = values.original[1].properties.minSoc;
let minSoc = Math.max(minSoc_A, minSoc_B);

values.properties.minSoc = minSoc
flow.set('minSoc_A', minSoc_A)
flow.set('minSoc_B', minSoc_B)
flow.set('minSoc', minSoc)


// socSet - select lowest one
let socSet_A = values.original[0].properties.socSet;
let socSet_B = values.original[1].properties.socSet;
let socSet = Math.min(socSet_A, socSet_B);

values.properties.socSet = socSet
flow.set('socSet_A', socSet_A)
flow.set('socSet_B', socSet_B)
flow.set('socSet', socSet)


// socLimit 	int 	0: Normal state, 1: Charge limit reached, 2: Discharge limit reached
const socLimit_A = values.original[0].properties.socLimit
const socLimit_B = values.original[1].properties.socLimit
let socLimit = 0

if (socLimit_A === 0 && socLimit_B === 0) {
    socLimit = 0
} else if (socLimit_A === 1 && socLimit_B === 1) {
    socLimit = 1
} else if (socLimit_A === 2 && socLimit_B === 2) {
    socLimit = 2
} else if (socLimit_A === 1 || socLimit_B === 1) {
    socLimit = 0
} else if (socLimit_A === 2 || socLimit_B === 2) {
    socLimit = 0
} else {
    socLimit = -1 // unknown
}
values.properties.socLimit = socLimit;

flow.set('socLimit', socLimit)
flow.set('socLimit_A', socLimit_A)
flow.set('socLimit_B', socLimit_B)


//// total battery percentage to send to HA

let electricLevel_A_calc = electricLevel_A
let electricLevel_B_calc = electricLevel_B

// to solve specific situation when one node drops % suddenly far below minSoc while the other one did not reach minSoc yet, or one is already below minSoc.
// this should make the higher battery still discharge towards minSoc. After that, SoC protection can come into action to charge the lowest one up towards minSoc.
if ((socLimit_A == 2) !== (socLimit_B == 2)) {
    if (socLimit_A == 2) {
        electricLevel_A_calc = minSoc / 10;
    } else {
        electricLevel_B_calc = minSoc / 10;
    }
}

if (((socLimit_A == 2) !== (socLimit_B == 2)) && (electricLevel_A_calc <= minSoc / 10 + 1 && electricLevel_B_calc <= minSoc / 10 + 1)) {   //XOR, when only one of both devices reached battery Empty state AND % not > minsoc+1
    // round up in a special case, so that minSoc will be reached when dischaging
    electricLevel = Math.ceil((electricLevel_A_calc + electricLevel_B_calc) / 2); // then we round up, so that discharging will continue till both are empty
} else {  
    // round down in the normal case
    electricLevel = Math.floor((electricLevel_A_calc + electricLevel_B_calc) / 2);
}
values.properties.electricLevel = electricLevel


// smartMode
// We will send 0 if one of the nodes is at 0 (then it needs to be corrected to 1 by an HA POST command)
// But in singleMode, if one is in smartmode=0 and the other 1, we say it is 1 (so that one device can go in Standby mode and HA does not correct it)
// Doc: https://github.com/Zendure/zenSDK/blob/main/docs/en_properties.md
//1: The setting parameter is not written to flash. After an unexpected power loss and restart, the device will use the value stored in flash. 
//0: The setting parameter is written to flash.

// also durin transition period send smartMode=1 to HA if at least one of devices has smartMode=1.
if ((currentTime - singleToDualModeTransition_start_timestamp < singleModeDeviceChangeTranstion_timer + 10) || (currentTime - dualMode_force_start_timestamp < singleModeDeviceChangeTranstion_timer + 10)) {  //check for transition being active
    deviceTransition_active = 1;
}

let smartMode_A = values.original[0].properties.smartMode;
let smartMode_B = values.original[1].properties.smartMode;
let smartMode;
if (singleMode_standby_device_A == 1 || singleMode_standby_device_B == 1 || deviceTransition_active == 1) {
    smartMode = Math.max(smartMode_A,smartMode_B);  // if at least one is in smartmode=1, send smartmode=1
} else {
    smartMode = smartMode_A * smartMode_B; // if at least one is in smartmode=0, send smartmode=0
}
values.properties.smartMode = smartMode;
flow.set('smartMode_A', smartMode_A)
flow.set('smartMode_B', smartMode_B)


// BatVolt
let BatVolt = (values.original[0].properties.BatVolt + values.original[1].properties.BatVolt) / 2;
values.properties.BatVolt = BatVolt

// remainOutTime
let remainOutTime = (values.original[0].properties.remainOutTime + values.original[1].properties.remainOutTime) / 2;
values.properties.remainOutTime = remainOutTime

// hyperTmp (take the highest value)
let hyperTmp_A = values.original[0].properties.hyperTmp;
let hyperTmp_B = values.original[1].properties.hyperTmp;
let hyperTmp = Math.max(hyperTmp_A, hyperTmp_B);
values.properties.hyperTmp = hyperTmp;


// chargeMaxLimit
let chargeMaxLimit = (chargeMaxLimit_A + chargeMaxLimit_B);
values.properties.chargeMaxLimit = chargeMaxLimit;
flow.set('chargeMaxLimit_A', chargeMaxLimit_A)
flow.set('chargeMaxLimit_B', chargeMaxLimit_B)

// inverseMaxPower (Maximum output power limit)
let inverseMaxPower = (inverseMaxPower_A + inverseMaxPower_B);
values.properties.inverseMaxPower = inverseMaxPower;
flow.set('inverseMaxPower_A', inverseMaxPower_A)
flow.set('inverseMaxPower_B', inverseMaxPower_B)

// packNum
let packNum = (values.original[0].properties.packNum + values.original[1].properties.packNum);
values.properties.packNum = packNum;

// rssi, use the lowest of both rssi's
let rssi = Math.min(values.original[0].properties.rssi, values.original[1].properties.rssi);
values.properties.rssi = rssi;

// is_error (normaal 0; als er een >0 is, dan is het dat)
let is_error = Math.max(values.original[0].properties.is_error, values.original[1].properties.is_error);
values.properties.is_error = is_error;


// save socStatus for both devices to a global variable (socStatus 	int 	0: No, 1: Calibrating)
let socStatus_A = values.original[0].properties.socStatus;
let socStatus_B = values.original[1].properties.socStatus;
flow.set('socStatus_A', socStatus_A)
flow.set('socStatus_B', socStatus_B)

// socStatus (0: No, 1: Calibrating)
let socStatus = Math.min(socStatus_A, socStatus_B);
values.properties.socStatus = socStatus;


//// Solar specific information
if (solarPowerInfo === 1) {

    // Solar Power
    values.properties.solarPower1 = values.original[0].properties.solarPower1;
    values.properties.solarPower2 = values.original[0].properties.solarPower2;
    values.properties.solarPower3 = values.original[0].properties.solarPower3;
    values.properties.solarPower4 = values.original[0].properties.solarPower4;
    // skip 5 and 6 because those are not present on current device models
    values.properties.solarPower7 = values.original[1].properties.solarPower1;
    values.properties.solarPower8 = values.original[1].properties.solarPower2;
    values.properties.solarPower9 = values.original[1].properties.solarPower3;
    values.properties.solarPower10 = values.original[1].properties.solarPower4;

}

// gridReverse; Reverse flow control (0-2) (RW); (Probable meaning: controls if you deliver power back to the grid from solar when battery is at 100%)
// "PV gaat enkel direct naar het net als batterij 100% is en gridReverse 1"
// Let's take the average value. Should be the same on both nodes.
let gridReverse_A = values.original[0].properties.gridReverse;
let gridReverse_B = values.original[1].properties.gridReverse;

let gridReverse = (gridReverse_A + gridReverse_B) / 2;
values.properties.gridReverse = gridReverse;

// batCalTime (op SF2400AC beschikbaar vanaf firmware V1.0.19)
// Kalibratie tijd in minuten vanaf 00:00 uur
let batCalTime_A = 0
let batCalTime_B = 0
let batCalTime = -1
if ("batCalTime" in values.original[0].properties && "batCalTime" in values.original[1].properties) {
    let batCalTime_A = values.original[0].properties.batCalTime;
    let batCalTime_B = values.original[1].properties.batCalTime;
    if (batCalTime_A == batCalTime_B) {
        batCalTime = batCalTime_A
    }

    values.properties.batCalTime = batCalTime;
    values.properties.batCalTime_1 = batCalTime_A;
    values.properties.batCalTime_2 = batCalTime_B;
}

//-----
// additions for proxy:

// Individual products (may be different when using two different models)
let product_A = values.original[0].product
let product_B = values.original[1].product
values.product_1 = product_A
values.product_2 = product_B

// serialnr
let sn = "0000-PROXY-0000"
sn_A = values.original[0].sn;
sn_B = values.original[1].sn;
values.sn = sn
values.sn_1 = sn_A
values.sn_2 = sn_B

// Additional socStatus for each Zendure device
values.properties.socStatus_1 = socStatus_A;
values.properties.socStatus_2 = socStatus_B;

// Additional socLimit for each Zendure device
values.properties.socLimit_1 = socLimit_A
values.properties.socLimit_2 = socLimit_B

// Additional battery percentage for each individual Zendure device
values.properties.electricLevel_1 = electricLevel_A
values.properties.electricLevel_2 = electricLevel_B

// Additional: add lastest posted power and posted to the both devices
values.properties.latestPowerCmd = latestPowerCmd;
values.properties.latestPowerCmd_1 = latestPowerCmd_1;
values.properties.latestPowerCmd_2 = latestPowerCmd_2;

// send smartmode status for the individual devices
values.properties.smartMode_1 = smartMode_A;
values.properties.smartMode_2 = smartMode_B;

// send temperature status for the individual devices
values.properties.hyperTmp_1 = hyperTmp_A;
values.properties.hyperTmp_2 = hyperTmp_B;

// outputPackPower - Vermogen Aansturing
values.properties.outputPackPower_1 = outputPackPower_A;
values.properties.outputPackPower_2 = outputPackPower_B;

// packInputPower - Vermogen Aansturing
values.properties.packInputPower_1 = packInputPower_A;
values.properties.packInputPower_2 = packInputPower_B;

// gridInputPower
values.properties.gridInputPower_1 = gridInputPower_A;
values.properties.gridInputPower_2 = gridInputPower_B;

// outputHomePower
values.properties.outputHomePower_1 = outputHomePower_A;
values.properties.outputHomePower_2 = outputHomePower_B;

// send singlemode active device status
let charging_limit_powerzero = (latestPowerCmd > 0 && socLimit === 1 && outputPackPower === 0)   // when limit reached do not wait for latestPowerCmd to become zero
let discharging_limit_powerzero = (latestPowerCmd < 0 && socLimit === 2 && packInputPower === 0) // when limit reached do not wait for latestPowerCmd to become zero

if (latestPowerCmd === 0 || charging_limit_powerzero || discharging_limit_powerzero) {
    values.properties.activeDevice = -1;   // -1: none active
} else if (singleMode === 1) {
    values.properties.activeDevice = singleMode_activedevice + 1;  // 1: device 1 active, 2: device 2 active
} else {
    values.properties.activeDevice = 0;   // 0: dual mode (both active)
}

// send equalMode status
if (equalMode === 1) {
    values.properties.equalMode = 1
} else {
    values.properties.equalMode = 0
}

// send alwaysDualMode status
if (alwaysDualMode === 1) {
    values.properties.alwaysDualMode = 1
} else {
    values.properties.alwaysDualMode = 0
}

// send DualModeDamper status
if (dualmode_damper_enable === 1) {
    values.properties.dualModeDamper = 1
} else {
    values.properties.dualModeDamper = 0
}

//-----

// delete from original data to keep the packet small
delete values.original;
delete msg.topic;

// put new payload in msg.payload
msg.payload = values;




return msg;

/* 
Use this example request to test:

 % curl -vX POST "http://192.168.2.246:1880/properties/write" -H "Content-Type: application/json" -d "{\"sn\": \"xxxxx\",\"properties\":{\"acMode\":1, \"inputLimit\":0}}"  

 % curl -vX POST "http://192.168.2.246:1880/properties/write" -H "Content-Type: application/json" -d "{\"sn\": \"xxxxx\",\"properties\":{\"acMode\":2, \"outputLimit\":1000}}"

*/ 




// read serial numbers and IP addresses from global variable (can be modified in block "Vul hier de Zendure IP adressen en serienummers in")
var snZendure1 = flow.get('snZendure1')||1;
var snZendure2 = flow.get('snZendure2')||1;
var ipZendure1 = flow.get('ipZendure1')||1;
var ipZendure2 = flow.get('ipZendure2')||1;

// load configurable variables (can be modified in block "Vul hier de Zendure IP adressen en serienummers in")
let maxPower_in = flow.get('maxPower_in')||800;
let maxPower_out = flow.get('maxPower_out')||800;
let tmp = flow.get('singleMode_enable');
var singleMode_enable = (tmp === undefined) ? 1 : tmp;    // needs special handling because it can be 0 or 1 (not needed if default is 0)
let balancingFactor = flow.get('balancingFactor')||1;
let balancingFactor_reduced = flow.get('balancingFactor_reduced') || 1;

// load global variables
var electricLevel_A = flow.get('electricLevel_A')||50;
var electricLevel_B = flow.get('electricLevel_B')||50;
var minSoc = flow.get('minSoc')||100;   // assumption: this is set the same for both devices
var socSet = flow.get('socSet')||1000;  // assumption: this is set the same for both devices
var singleMode_previous = flow.get('singleMode')||0;
var singleMode_change_device_diff = flow.get('singleMode_change_device_diff')||1;
var socStatus_A = flow.get('socStatus_A')||0;
var socStatus_B = flow.get('socStatus_B')||0;
var smartMode_A = flow.get('smartMode_A') || 0;
var smartMode_B = flow.get('smartMode_B') || 0;
var manualMode_messageRepeat = flow.get('manualMode_messageRepeat')||0;
var latestPowerMessage_timestamp_epoch = flow.get('latestPowerMessage_timestamp_epoch')||1;
var socLimit_A = flow.get('socLimit_A')||0;
var socLimit_B = flow.get('socLimit_B')||0;
var latestPowerCmd_1_zero_timestamp = flow.get('latestPowerCmd_1_zero_timestamp')||1;
var latestPowerCmd_2_zero_timestamp = flow.get('latestPowerCmd_2_zero_timestamp')||1;
var singleMode_standby_device_A = flow.get('singleMode_standby_device_A')||0;
var singleMode_standby_device_B = flow.get('singleMode_standby_device_B')||0;
var acMode_previous = flow.get('acMode')||0;
var singleMode_activedevice_previous = flow.get('singleMode_activedevice')||0;
var latestPowerCmd_previous = flow.get('latestPowerCmd')||0;
var latestPowerCmd_1_previous = flow.get('latestPowerCmd_1')||0;
var latestPowerCmd_2_previous = flow.get('latestPowerCmd_2')||0;
var singleModeDeviceChangeTranstion_timer = flow.get('singleModeDeviceChangeTranstion_timer') || 20;
var dualMode_force_start_timestamp = flow.get('dualMode_force_start_timestamp') || 1;
var dualMode_force_original_device = flow.get('dualMode_force_original_device') || 0;
var singleToDualModeTransition_start_timestamp = flow.get('singleToDualModeTransition_start_timestamp') || 1;
var singleToDualModeTransition_original_device = flow.get('singleToDualModeTransition_original_device') || 0;
var dualmode_damper_enable = flow.get('dualmode_damper_enable')||0;
var dualmode_damper_timer = flow.get('dualmode_damper_timer')||0;
var dualmode_damper_amount = flow.get('dualmode_damper_amount')||0;
var dualmode_damper_starttime = flow.get('dualmode_damper_starttime')||1;
var dualmode_damper_active_previous = flow.get('dualmode_damper_active_previous')||0;

// initializing equalMode settings
var dualmode_force_charging = 0;
var dualmode_force_discharging = 0;
var dualmode_equal_power_charging = 0;
var dualmode_equal_power_discharging = 0;

var equalMode = flow.get('equalMode') || 0;
var alwaysDualMode = flow.get('alwaysDualMode') || 0;

//node.warn("equalMode is " + equalMode);

// set the settings to be used for equalMode
if (equalMode === 1) {
    dualmode_force_charging = 1
    dualmode_force_discharging = 1
    dualmode_equal_power_charging = 1
    dualmode_equal_power_discharging = 1

} else if (alwaysDualMode === 1) {
    dualmode_force_charging = 1
    dualmode_force_discharging = 1
    dualmode_equal_power_charging = 0
    dualmode_equal_power_discharging = 0

} else {
    dualmode_force_charging = 0
    dualmode_force_discharging = 0
    dualmode_equal_power_charging = 0
    dualmode_equal_power_discharging = 0
}




// load global variables coming from node "Check Stuff"
let singleMode_upperlimit_in = flow.get('singleMode_upperlimit_in') || 800;
let singleMode_upperlimit_out = flow.get('singleMode_upperlimit_out') || 800;
let singleMode_lowerlimit_in = flow.get('singleMode_lowerlimit_in') || 500;
let singleMode_lowerlimit_out = flow.get('singleMode_lowerlimit_out') || 500;



// initialization of variables
let boostAmount = 0
let inputLimit = 0
let outputLimit = 0
let Power_A = 0
let Power_B = 0
let Avail_A = 0
let Avail_B = 0
let Avail_Total = 0
let latestPowerMessage = ""
let currentTime = Math.floor(Date.now() / 1000)
let singleMode_change_device_diff_used = 1
let latestPowerCmd = 0
let latestPowerCmd_1 = 0
let latestPowerCmd_2 = 0
let acMode = 0
let smartMode_1_only_packet = 0
let singleMode = singleMode_previous
let singleMode_activedevice = singleMode_activedevice_previous //default to previous
let forcedDualModeActive = 0
let singleToDualModeTransition_active = 0
let chargeMaxLimit = 0
let inverseMaxPower = 0
let power_message = 0
let skip_inputLimit = 0
let skip_outputLimit = 0
let dualmode_damper_active = 0

// Define target servers
let server1 = "http://" + ipZendure1 + "/properties/write";
let server2 = "http://" + ipZendure2 + "/properties/write";

// The incoming POST body
let data = msg.payload;  //changed back to non-deep clone for speed optimization
//let data = JSON.parse(JSON.stringify(msg.payload)); 


// store equalMode setting from instruction message (POST)
