                } else { //device B is active
                Avail_B = 1
                Avail_A = 0
                }
            }
        }

        //calculation for power A and B
        if ((Avail_A == Avail_B) || (dualmode_equal_power_discharging === 1 && (singleMode === 0))) {
            Power_A = Math.floor(outputLimit / 2);
            if (Power_A > maxPower_out) {
                Power_A = maxPower_out
            }
            Power_B = Power_A
        } else {   // unequal charge available to discharge
                    // start with the highest available one, determine it's power, proportional to available storage
            Avail_Total = Avail_A + Avail_B
            if (Avail_A > Avail_B) {
                Power_A = Math.floor((Avail_A / Avail_Total) * outputLimit * balancingFactor)
                if (Power_A > outputLimit) {
                    Power_A = outputLimit
                }
                if (Power_A > maxPower_out) {
                    Power_A = maxPower_out
                } 
                Power_B = outputLimit - Power_A  // the smaller one takes the rest
                if (Power_B > maxPower_out) {
                    Power_B = maxPower_out
                }
            } else if (Avail_B > Avail_A) {
                Power_B = Math.floor((Avail_B / Avail_Total) * outputLimit * balancingFactor)
                if (Power_B > outputLimit) {
                    Power_B = outputLimit
                }
                if (Power_B > maxPower_out) {
                    Power_B = maxPower_out
                } 
                Power_A = outputLimit - Power_B
                if (Power_A > maxPower_out) {
                    Power_A = maxPower_out
                } 
            }
        }

