var minSoc_unequal_error = flow.get('minSoc_unequal_error') || 0;
var socSet_unequal_error = flow.get('socSet_unequal_error') || 0;
var singleMode_upperlimit_percent = flow.get('singleMode_upperlimit_percent') || 100;
var singleMode_lowerlimit_percent = flow.get('singleMode_lowerlimit_percent') || 40;
var maxPower_in = flow.get('maxPower_in') || 0;
var maxPower_out = flow.get('maxPower_out') || 0;
var minSoc_A = flow.get('minSoc_A') || 0;
var minSoc_B = flow.get('minSoc_B') || 0;
var socSet_A = flow.get('socSet_A') || 0;
var socSet_B = flow.get('socSet_B') || 0;
var payloadError = flow.get('payloadError') || 0;
var payloadError_previous = flow.get('payloadError_previous') || 0;



//throw a warning if there are multiple errors in payload counted by "Get Response Handling" node since previous check
let payloadError_diff = payloadError - payloadError_previous;
if (payloadError_diff > 1) {
    node.warn("Mogelijk communicatieprobleem tussen Node-Red en de Zendure devices!")
}
flow.set('payloadError_previous', payloadError)


//throw a warning if chargeMaxLimit or inverseMaxPower is not the same on both devices
if (chargeMaxLimit_A !== chargeMaxLimit_B) {
    chargeMaxLimit_unequal_error = chargeMaxLimit_unequal_error + 1;
} else {
    chargeMaxLimit_unequal_error = 0;
}
flow.set('chargeMaxLimit_unequal_error', chargeMaxLimit_unequal_error)

if (chargeMaxLimit_unequal_error > 2) {
    node.warn("Max. Oplaadvermogen is niet gelijk op beide devices: " + chargeMaxLimit_A + " en " + chargeMaxLimit_B);
}

if (inverseMaxPower_A !== inverseMaxPower_B) {
    inverseMaxPower_unequal_error = inverseMaxPower_unequal_error + 1;
} else {
    inverseMaxPower_unequal_error = 0;
}
flow.set('inverseMaxPower_unequal_error', inverseMaxPower_unequal_error)

if (inverseMaxPower_unequal_error > 2) {
    node.warn("Max. Ontlaadvermogen is niet gelijk op beide devices: " + inverseMaxPower_A + " en " + inverseMaxPower_B);
}



//throw a warning if minSoc or socSet is not the same on both devices
if (minSoc_A !== minSoc_B) {
    minSoc_unequal_error = minSoc_unequal_error + 1;
} else {
    minSoc_unequal_error = 0;
}
flow.set('minSoc_unequal_error', minSoc_unequal_error)

if (minSoc_unequal_error > 6) {
    node.warn("Minimale Laadpercentage is niet gelijk op beide devices: " + minSoc_A / 10 + "% en " + minSoc_B / 10 + "%");
}

if (socSet_A !== socSet_B) {
    socSet_unequal_error = socSet_unequal_error + 1;
} else {
    socSet_unequal_error = 0;
}
flow.set('socSet_unequal_error', socSet_unequal_error)

if (socSet_unequal_error > 6) {
    node.warn("Maximale Laadpercentage is niet gelijk op beide devices: " + socSet_A / 10 + "% en " + socSet_B / 10 + "%");
}




// This was taken out of block "GET Response handling", to not slow that down unecessarily.
// We calculate these values here. Due to lower frequency it will take a bit more time to adjust the values after changing 
// the max power, but that is not done often anyway.
//Calculate singleMode thresholds power (Watt) based on maxpower
// singleMode thresholds can be different for in and out directions, depending on maxpower in that direction
let singleMode_upperlimit_in = singleMode_upperlimit_percent / 100 * maxPower_in
let singleMode_upperlimit_out = singleMode_upperlimit_percent / 100 * maxPower_out
let singleMode_lowerlimit_in = singleMode_lowerlimit_percent / 100 * maxPower_in
let singleMode_lowerlimit_out = singleMode_lowerlimit_percent / 100 * maxPower_out
flow.set('singleMode_upperlimit_in', singleMode_upperlimit_in)
flow.set('singleMode_upperlimit_out', singleMode_upperlimit_out)
flow.set('singleMode_lowerlimit_in', singleMode_lowerlimit_in)
flow.set('singleMode_lowerlimit_out', singleMode_lowerlimit_out)




return null;

// read IP addresses from global variable
var ipZendure1 = flow.get('ipZendure1')||1;
var ipZendure2 = flow.get('ipZendure2')||1;


// Define target servers
let server1 = "http://" + ipZendure1 + "/properties/report";
let server2 = "http://" + ipZendure2 + "/properties/report";


// Build the message
let msg1 = {
    method: "GET",
    url: server1,
    headers: { "Content-Type": "application/json" },
};

let msg2 = {
    method: "GET",
    url: server2,
    headers: { "Content-Type": "application/json" },
};



return [msg1, msg2];

/*
Fetch the serialnr from the Zendure devices and put in a global variable.
*/

var payloadError = flow.get('payloadError') || 0;


// exit gracefully in case of error and count the error to a global variable
if (!msg.payload) {
    payloadError = payloadError + 1;
    flow.set('payloadError', payloadError);
    return null;
}


let data = JSON.parse(JSON.stringify(msg.payload || {}));

let snZendure1 = data.sn || "0";

if (snZendure1 !== "0") {
    flow.set('snZendure1', snZendure1);
    //node.warn("snZendure1 is " + snZendure1);
}



return null;

/*
Fetch the serialnr from the Zendure devices and put in a global variable.
*/

var payloadError = flow.get('payloadError') || 0;


// exit gracefully in case of error and count the error to a global variable
if (!msg.payload) {
    payloadError = payloadError + 1;
    flow.set('payloadError', payloadError);
    return null;
}


let data = JSON.parse(JSON.stringify(msg.payload || {}));

let snZendure2 = data.sn || "0";

if (snZendure2 !== "0") {
    flow.set('snZendure2', snZendure2);
    //node.warn("snZendure2 is " + snZendure2);
}



return null;

// to cancel the timeout
msg.reset = true;

msg.topic = msg._msgid;

return msg;

let key = "http_" + msg._msgid;
let http = flow.get(key);

if (!http) {
    return null; // already handled
}

//node.warn("Zendure timeout");

msg.req = http.req;
msg.res = http.res;

flow.set(key, null);

msg.statusCode = 504;
msg.payload = { error: "Gateway Timeout" };

return msg;
